using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    [ColumnName("Score")]
    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public record TicketRequest(string Subject, string Description, int Priority);

public record TicketClassificationResult(
    string Category,
    float Confidence,
    Dictionary<string, float> Scores);

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public static class ModelTrainerService
{
    public static string[] TrainAndEvaluate(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        Console.WriteLine("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on held-out test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        Console.WriteLine("========== Evaluation Metrics ==========");
        Console.WriteLine($"  MacroAccuracy:    {metrics.MacroAccuracy:F4}");
        Console.WriteLine($"  MicroAccuracy:    {metrics.MicroAccuracy:F4}");
        Console.WriteLine($"  LogLoss:          {metrics.LogLoss:F4}");
        Console.WriteLine($"  LogLossReduction: {metrics.LogLossReduction:F4}");
        Console.WriteLine("=========================================");

        if (metrics.ConfusionMatrix is not null)
        {
            Console.WriteLine(metrics.ConfusionMatrix.GetFormattedConfusionTable());
        }

        // Extract label names from the model's output schema for score mapping
        var outputSchema = model.GetOutputSchema(split.TrainSet.Schema);
        var labelColumn = outputSchema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        labelColumn.GetSlotNames(ref slotNames);
        var classNames = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

        mlContext.Model.Save(model, data.Schema, modelPath);
        Console.WriteLine($"Model saved to {modelPath}");

        return classNames;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;
    private readonly string[] _classNames;

    public TicketClassifierController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool,
        [FromKeyedServices("classNames")] string[] classNames)
    {
        _predictionPool = predictionPool;
        _classNames = classNames;
    }

    [HttpPost("classify")]
    public IActionResult Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var scores = new Dictionary<string, float>();
        for (int i = 0; i < _classNames.Length && i < prediction.Score.Length; i++)
        {
            scores[_classNames[i]] = prediction.Score[i];
        }

        return Ok(new TicketClassificationResult(
            Category: prediction.Category,
            Confidence: prediction.Score.Max(),
            Scores: scores));
    }
}

