using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");

// Train model and capture class labels for score mapping
var classNames = ModelTrainerService.TrainAndEvaluate(dataPath, modelPath);

// Thread-safe prediction engine pool (PredictionEngine is not thread-safe)
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(modelPath);

builder.Services.AddKeyedSingleton("classNames", classNames);

var app = builder.Build();
app.MapControllers();
app.Run();

